class VersionChecker {
    constructor() {
        this.currentVersion = localStorage.getItem('app_version') || '1.0.0';
        this.lastCheck = parseInt(localStorage.getItem('last_version_check') || '0', 10);
        this.checkInterval = 0;
        this.isUpdating = false;
        this.serviceWorkerSupported = 'serviceWorker' in navigator;
    }

    static isUpdatesTabContext() {
        if (typeof window === 'undefined') return false;
        const path = (window.location.pathname || '').toLowerCase();
        const isAccount = path.endsWith('/account.php') || path === '/account.php' || path === 'account.php';
        const tab = new URLSearchParams(window.location.search).get('tab');
        return isAccount && tab === 'updates';
    }

    async checkVersion() {
        if (this.isUpdating) return false;

        const now = Date.now();
        if (now - this.lastCheck < this.checkInterval) return false;

        try {
            const response = await fetch('/version.json?t=' + now);
            if (!response.ok) throw new Error('Version check failed');

            const payload = await response.json();
            const latest = payload.version;

            if (this.compareVersions(latest, this.currentVersion) > 0) {
                this.showUpdatePrompt(latest, payload.changelog, payload.critical || false);
                return true;
            }

            localStorage.setItem('last_version_check', now.toString());
            return false;
        } catch (error) {
            return false;
        }
    }

    compareVersions(a, b) {
        const va = String(a || '').split('.').map(Number);
        const vb = String(b || '').split('.').map(Number);

        for (let i = 0; i < Math.max(va.length, vb.length); i++) {
            const na = va[i] || 0;
            const nb = vb[i] || 0;
            if (na !== nb) return na > nb ? 1 : -1;
        }

        return 0;
    }

    showUpdatePrompt(newVersion, changelog, critical = false) {
        const modal = document.createElement('div');
        modal.className = 'version-update-modal';

        const laterButton = `<button class="btn-update-later">${critical ? 'Закрыть' : 'Напомнить позже'}</button>`;

        modal.innerHTML = `
            <div class="version-update-content">
                <h3 class="${critical ? 'critical-update' : 'regular-update'}">
                    ${critical ? '🚨 КРИТИЧЕСКОЕ ОБНОВЛЕНИЕ' : '🔄 Доступно обновление'}
                </h3>
                <p>Текущая версия: <strong>${this.currentVersion}</strong></p>
                <p>Новая версия: <strong>${newVersion}</strong></p>
                ${changelog ? `
                <div class="changelog">
                    <strong>Что нового:</strong>
                    <div>${changelog}</div>
                </div>` : ''}
                <div class="version-buttons">
                    <button class="btn-update-now ${critical ? 'critical-btn' : ''}">Обновить сейчас</button>
                    ${laterButton}
                </div>
            </div>
        `;

        document.body.insertAdjacentElement('afterbegin', modal);

        const closeModal = (saveReminder = true) => {
            if (saveReminder) {
                localStorage.setItem('last_version_check', (Date.now() - this.checkInterval + 900000).toString());
            }
            document.removeEventListener('keydown', onKeyDown);
            if (modal.parentNode) modal.remove();
        };

        const onKeyDown = (event) => {
            if (event.key === 'Escape') {
                closeModal(true);
            }
        };
        document.addEventListener('keydown', onKeyDown);

        const updateNow = modal.querySelector('.btn-update-now');
        if (updateNow) {
            updateNow.addEventListener('click', () => {
                this.performUpdate();
                closeModal(false);
            });
        }

        const remindLater = modal.querySelector('.btn-update-later');
        if (remindLater) {
            remindLater.addEventListener('click', () => closeModal(true));
        }

        modal.addEventListener('click', (event) => {
            if (event.target === modal) {
                closeModal(true);
            }
        });
    }

    async performUpdate() {
        this.isUpdating = true;

        try {
            this.showUpdateInProgress();
            await fetch('/clear-cache.php?t=' + Date.now(), { cache: 'no-store' });
            await this.unregisterServiceWorker();
            await this.clearAllCaches();

            const response = await fetch('/version.json?t=' + Date.now(), {
                headers: {
                    'Cache-Control': 'no-cache',
                    Pragma: 'no-cache',
                },
                cache: 'no-store',
            });

            if (response.ok) {
                const payload = await response.json();
                localStorage.setItem('app_version', payload.version);
            }

            localStorage.setItem('last_version_check', Date.now().toString());

            setTimeout(() => {
                window.location.href = window.location.origin + '?force_reload=' + Date.now();
            }, 2000);
        } catch (error) {
            this.isUpdating = false;
            this.showUpdateError();
        }
    }

    async unregisterServiceWorker() {
        if (!this.serviceWorkerSupported) return;

        try {
            const registration = await navigator.serviceWorker.getRegistration();
            if (registration) await registration.unregister();
        } catch (error) {
            // no-op
        }
    }

    async clearAllCaches() {
        if ('caches' in window) {
            try {
                const keys = await caches.keys();
                await Promise.all(keys.map((key) => caches.delete(key)));
            } catch (error) {
                // no-op
            }
        }

        if (this.serviceWorkerSupported) {
            try {
                const registration = await navigator.serviceWorker.getRegistration();
                if (registration && registration.active) {
                    registration.active.postMessage({ type: 'CLEAR_CACHE' });
                }
            } catch (error) {
                // no-op
            }
        }

        const preserved = ['user_data', 'auth_token', 'settings', 'app_version', 'last_version_check'];
        Object.keys(localStorage).forEach((key) => {
            if (!preserved.includes(key)) localStorage.removeItem(key);
        });

        sessionStorage.clear();
    }

    showUpdateInProgress() {
        const progress = document.createElement('div');
        progress.className = 'update-progress';
        progress.innerHTML = `
            <div class="progress-content">
                <div class="spinner"></div>
                <p>Обновление приложения...</p>
                <p>Пожалуйста, подождите</p>
            </div>
        `;
        document.body.appendChild(progress);
    }

    showUpdateError() {
        const box = document.createElement('div');
        box.className = 'update-error';
        box.innerHTML = `
            <h3>❌ Ошибка обновления</h3>
            <p>Не удалось выполнить обновление. Пожалуйста, попробуйте перезагрузить страницу вручную.</p>
            <button onclick="window.location.reload(true)">Перезагрузить</button>
        `;
        document.body.appendChild(box);
    }

    init() {
        this.checkVersion();

        document.addEventListener('visibilitychange', () => {
            if (document.visibilityState === 'visible') this.checkVersion();
        });

        window.addEventListener('online', () => {
            this.checkVersion();
        });

        setInterval(() => {
            this.checkVersion();
        }, 7200000);
    }
}

if (typeof window !== 'undefined' && VersionChecker.isUpdatesTabContext()) {
    window.versionChecker = new VersionChecker();
    document.addEventListener('DOMContentLoaded', () => {
        window.versionChecker.init();
    });
}
